127 static Value *simplifyCmpSelTrueCase(CmpPredicate Pred, Value *LHS, Value *RHS,
128                                      Value *Cond, const SimplifyQuery &Q,
129                                      unsigned MaxRecurse) {
130   return simplifyCmpSelCase(Pred, LHS, RHS, Cond, Q, MaxRecurse,
