4759         match(CmpRHS, m_AllOnes())) {
4760       // (X & Y) == -1 implies X == -1 and Y == -1.
4761       if (Value *V = simplifySelectWithEquivalence(
4762               {{X, CmpRHS}, {Y, CmpRHS}}, TrueVal, FalseVal, Q, MaxRecurse))
4763         return V;
4764     }
4765   }
4766 
4767   return nullptr;
4768 }
