209 Intrinsic::ID llvm::getVectorIntrinsicIDForCall(const CallInst *CI,
210                                                 const TargetLibraryInfo *TLI) {
211   Intrinsic::ID ID = getIntrinsicForCallSite(*CI, TLI);
